  sessionBody: { flex: 1, display: "flex", flexDirection: "row", flexWrap: "wrap", gap: 6, alignItems: "center" } as React.CSSProperties,
  sessionEvent: { fontSize: 12, fontWeight: 600 } as React.CSSProperties,
